package main

import (
    "fmt"
    "io"
    "net/http"
    "os"
    "path/filepath"
    "strings"
)

func uploadHandler(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        return
    }

    err := r.ParseMultipartForm(10 << 20) // 10 MB limit
    if err != nil {
        http.Error(w, "Failed to parse form", http.StatusBadRequest)
        return
    }

    file, header, err := r.FormFile("file")
    if err != nil {
        http.Error(w, "No file uploaded", http.StatusBadRequest)
        return
    }
    defer file.Close()

    // Check file extension
    ext := strings.ToLower(filepath.Ext(header.Filename))
    allowedExts := []string{".jpg", ".png", ".pdf"}
    allowed := false
    for _, allowedExt := range allowedExts {
        if ext == allowedExt {
            allowed = true
            break
        }
    }
    if !allowed {
        http.Error(w, "File type not allowed", http.StatusBadRequest)
        return
    }

    // Save file to a fixed directory
    uploadDir := "./uploads"
    if _, err := os.Stat(uploadDir); os.IsNotExist(err) {
        os.Mkdir(uploadDir, 0755)
    }
    filePath := filepath.Join(uploadDir, header.Filename)
    dst, err := os.Create(filePath)
    if err != nil {
        http.Error(w, "Failed to save file", http.StatusInternalServerError)
        return
    }
    defer dst.Close()

    _, err = io.Copy(dst, file)
    if err != nil {
        http.Error(w, "Failed to copy file", http.StatusInternalServerError)
        return
    }

    fmt.Fprintf(w, "File uploaded successfully: %s", header.Filename)
}

func main() {
    http.HandleFunc("/upload", uploadHandler)
    http.ListenAndServe(":8080", nil)
}

class PluginLoader {
  constructor() {
    this.plugins = {};
    this.loadedPlugins = [];
  }

  loadPlugin(name, plugin) {
    if (typeof plugin !== 'function') {
      console.error('Plugin must be a function');
      return;
    }
    this.plugins[name] = plugin;
    this.loadedPlugins.push(name);
    console.log(`Plugin ${name} loaded`);
  }

  unloadPlugin(name) {
    if (this.plugins[name]) {
      delete this.plugins[name];
      const index = this.loadedPlugins.indexOf(name);
      if (index > -1) {
        this.loadedPlugins.splice(index, 1);
      }
      console.log(`Plugin ${name} unloaded`);
    } else {
      console.error(`Plugin ${name} not found`);
    }
  }

  executePlugin(name, ...args) {
    if (this.plugins[name]) {
      return this.plugins[name](...args);
    } else {
      console.error(`Plugin ${name} not loaded`);
      return null;
    }
  }

  listPlugins() {
    return this.loadedPlugins;
  }
}

// 示例使用
const loader = new PluginLoader();
loader.loadPlugin('logger', (msg) => console.log(`Log: ${msg}`));
