package main

import (
    "fmt"
    "sync"
    "time"
)

type DistributedLock struct {
    mu       sync.Mutex
    locked   bool
    ownerID  string
    expiry   time.Time
}

func NewDistributedLock() *DistributedLock {
    return &DistributedLock{}
}

func (dl *DistributedLock) Acquire(ownerID string, timeout time.Duration) bool {
    dl.mu.Lock()
    defer dl.mu.Unlock()

    if !dl.locked {
        dl.locked = true
        dl.ownerID = ownerID
        dl.expiry = time.Now().Add(timeout)
        return true
    }

    if time.Now().After(dl.expiry) {
        dl.locked = true
        dl.ownerID = ownerID
        dl.expiry = time.Now().Add(timeout)
        return true
    }

    return false
}

func (dl *DistributedLock) Release(ownerID string) {
    dl.mu.Lock()
    defer dl.mu.Unlock()

    if dl.ownerID == ownerID {
        dl.locked = false
        dl.ownerID = ""
    }
}

func main() {
    lock := NewDistributedLock()
    var wg sync.WaitGroup

    for i := 0; i < 3; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            if lock.Acquire(fmt.Sprintf("owner%d", id), 2*time.Second) {
                fmt.Printf("Lock acquired by owner%d\n", id)
                time.Sleep(1 * time.Second)
                lock.Release(fmt.Sprintf("owner%d", id))
            } else {
                fmt.Printf("Failed to acquire lock for owner%d\n", id)
            }
        }(i)
    }

    wg.Wait()
}

