public class ErrorWrapper {
    private static final Logger logger = LoggerFactory.getLogger(ErrorWrapper.class);

    public static String wrapError(String message, Throwable cause) {
        if (message == null) {
            message = "An error occurred";
        }
        String wrappedMessage = "Error: " + message;
        if (cause != null) {
            wrappedMessage += " (Caused by: " + cause.getMessage() + ")";
        }
        logger.error(wrappedMessage, cause);
        return wrappedMessage;
    }

    public static void main(String[] args) {
        try {
            int result = 10 / 0;
        } catch (ArithmeticException e) {
            String error = wrapError("Division by zero", e);
            System.out.println(error);
        }
    }
}

