type Cache struct {
    data map[string]string
}

func NewCache() *Cache {
    return &Cache{
        data: make(map[string]string),
    }
}

func (c *Cache) Get(key string) (string, error) {
    value, exists := c.data[key]
    if !exists {
        return "", errors.New("key not found")
    }
    return value, nil
}

func (c *Cache) Set(key, value string) {
    c.data[key] = value
}

func ReadFromCache(c *Cache, key string) string {
    val, err := c.Get(key)
    if err != nil {
        return "default_value"
    }
    return val
}

func ProcessRequest(c *Cache, key string) {
    result := ReadFromCache(c, key)
    if result == "" {
        fmt.Println("Cache miss, fetching from database...")
    } else {
        fmt.Printf("Cache hit: %s\n", result)
    }
}

func main() {
    cache := NewCache()
