use std::collections::HashMap;
use std::time::{Duration, Instant};

struct Aggregator {
    data: HashMap<String, Vec<i32>>,
    last_aggregation: Instant,
}

impl Aggregator {
    fn new() -> Self {
        Aggregator {
            data: HashMap::new(),
            last_aggregation: Instant::now(),
        }
    }

    fn add_data(&mut self, key: String, value: i32) {
        self.data.entry(key).or_insert_with(Vec::new).push(value);
    }

    fn aggregate(&mut self) -> HashMap<String, i32> {
        let mut result = HashMap::new();
        for (key, values) in &self.data {
            let sum: i32 = values.iter().sum();
            result.insert(key.clone(), sum);
        }
        self.data.clear();
        self.last_aggregation = Instant::now();
        result
    }

    fn run_timer(&mut self, interval_secs: u64) {
        loop {
            std::thread::sleep(Duration::from_secs(interval_secs));
            let aggregated = self.aggregate();
            println!("Aggregated data: {:?}", aggregated);
        }
    }
}

fn main() {
    let mut agg = Aggregator::new();
    agg.add_data("metric_a".to_string(), 10);
    agg.add_data("metric_b".to_string(), 20);
    agg.run_timer(5);
}

