interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

function parseApiResponse<T>(response: ApiResponse<T>): T | null {
  if (!response.success) {
    console.error('API call failed:', response.error || 'Unknown error');
    return null;
  }

  if (response.data === undefined) {
    console.warn('API succeeded but data is undefined');
    return null;
  }

  // Type guard to ensure data is of type T
