### 改进代码
```go
package main

import (
	"errors"
	"fmt"
	"image"
	"image/jpeg"
	"os"
	"path/filepath"
)

func processImages(inputDir string, outputDir string, scaleFactor int) error {
	files, err := os.ReadDir(inputDir)
	if err != nil {
		return fmt.Errorf("failed to read input directory: %w", err)
	}

	var processingErrors []error
	for _, file := range files {
		ext := filepath.Ext(file.Name())
		if ext != ".jpg" && ext != ".jpeg" {
			continue
		}

		imgPath := filepath.Join(inputDir, file.Name())
		imgFile, err := os.Open(imgPath)
		if err != nil {
			processingErrors = append(processingErrors, fmt.Errorf("open %s: %w", imgPath, err))
			continue
		}

		img, _, err := image.Decode(imgFile)
		imgFile.Close() // 立即关闭文件
		if err != nil {
			processingErrors = append(processingErrors, fmt.Errorf("decode %s: %w", imgPath, err))
			continue
		}

		outputPath := filepath.Join(outputDir, "resized_"+file.Name())
		outputFile, err := os.Create(outputPath)
		if err != nil {
			processingErrors = append(processingErrors, fmt.Errorf("create %s: %w", outputPath, err))
			continue
		}

		bounds := img.Bounds()
		newWidth := bounds.Dx() / scaleFactor
		newHeight := bounds.Dy() / scaleFactor
		newImg := image.NewRGBA(image.Rect(0, 0, newWidth, newHeight))
		for y := bounds.Min.Y; y < bounds.Max.Y; y += scaleFactor {
			for x := bounds.Min.X; x < bounds.Max.X; x += scaleFactor {
				newImg.Set(x/scaleFactor, y/scaleFactor, img.At(x, y))
			}
		}

		err = jpeg.Encode(outputFile, newImg, nil)
		outputFile.Close() // 立即关闭文件
		if err != nil {
			processingErrors = append(processingErrors, fmt.Errorf("encode %s: %w", outputPath, err))
			continue
		}
	}

	if len(processingErrors) > 0 {
		return errors.New("some images failed to process: " + fmt.Sprint(processingErrors))
	}
	return nil
}

func main() {
	err := processImages("./input", "./output", 2)
	if err != nil {
		fmt.Println("Error processing images:", err)
	}
}
```

### 最佳实践
1. **及时释放资源**：在循环中处理文件时，避免使用 `defer` 关闭文件，而应在使用后立即调用 `Close()`，以防止资源泄漏和性能问题。
2. **统一错误处理**：收集和处理错误时，使用结构化的方式（如错误切片）并返回聚合错误，以提高代码的可维护性和调试效率。
3. **参数化配置**：将硬编码值（如文件扩展名、缩放因子）提取为参数或常量，使代码更灵活，易于适应需求变化。

