func processWithTimeout(ctx context.Context, data string) error {
    // 创建一个带超时的子context
    ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
    defer cancel() // 确保资源释放

    // 模拟一个耗时操作
    done := make(chan error, 1)
    go func() {
        // 模拟处理逻辑
        time.Sleep(3 * time.Second)
        if data == "" {
            done <- fmt.Errorf("data cannot be empty")
            return
        }
        fmt.Printf("Processed: %s\n", data)
        done <- nil
    }()

    // 等待操作完成或超时/取消
    select {
    case err := <-done:
        return err
    case <-ctx.Done():
        return fmt.Errorf("operation timed out or canceled: %v", ctx.Err())
    }
}

func main() {
    ctx := context.Background()
    err := processWithTimeout(ctx, "test data")
    if err != nil {
        fmt.Printf("Error: %v\n", err)
    } else {
        fmt.Println("Success")
    }
}

