```javascript
const nodemailer = require('nodemailer');
require('dotenv').config(); // 假设使用 dotenv 管理环境变量

async function sendPasswordResetEmail(userEmail, resetToken) {
  // 输入验证
  if (!userEmail || typeof userEmail !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(userEmail)) {
    throw new Error('Invalid email address');
  }
  if (!resetToken || typeof resetToken !== 'string' || resetToken.length < 10) {
    throw new Error('Invalid reset token');
  }

  const transporter = nodemailer.createTransport({
    service: 'gmail',
    auth: {
      user: process.env.EMAIL_USER, // 从环境变量读取
      pass: process.env.EMAIL_PASS  // 从环境变量读取
    }
  });

  const resetLink = `https://example.com/reset-password?token=${encodeURIComponent(resetToken)}`; // 使用 HTTPS 和编码
  const mailOptions = {
    from: process.env.EMAIL_USER,
    to: userEmail,
    subject: 'Password Reset Request',
    text: `Click this link to reset your password: ${resetLink}`,
    html: `<p>Click <a href="${resetLink}">here</a> to reset your password.</p>` // 添加 HTML 版本以提升用户体验
  };

  try {
    await transporter.sendMail(mailOptions);
    console.log('Password reset email sent to:', userEmail);
  } catch (error) {
    console.error('Error sending email:', error);
    throw error; // 重新抛出错误以便上层处理
  }
}

// Example usage
