public class LogAnalyzer {
    private List<String> logs;
    private Map<String, Integer> errorCounts;

    public LogAnalyzer(List<String> logs) {
        this.logs = logs;
        this.errorCounts = new HashMap<>();
    }

    public void analyzeLogs() {
        for (String log : logs) {
            if (log.contains("ERROR")) {
                String errorType = extractErrorType(log);
                if (errorCounts.containsKey(errorType)) {
                    errorCounts.put(errorType, errorCounts.get(errorType) + 1);
                } else {
                    errorCounts.put(errorType, 1);
                }
            }
        }
    }

    private String extractErrorType(String log) {
        // 假设错误类型在日志中以特定格式出现，例如 "ERROR: Database connection failed"
        String[] parts = log.split(":");
        if (parts.length > 1) {
            return parts[1].trim();
        }
        return "Unknown";
    }

    public void printStatistics() {
        for (Map.Entry<String, Integer> entry : errorCounts.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }

    public static void main(String[] args) {
        List<String> sampleLogs = Arrays.asList(
            "INFO: System started",
            "ERROR: Database connection failed",
            "WARN: High memory usage",
            "ERROR: Database connection failed",
            "ERROR: File not found"
        );
        LogAnalyzer analyzer = new LogAnalyzer(sampleLogs);
        analyzer.analyzeLogs();
        analyzer.printStatistics();
    }
}

