const SESSION_KEY = 'ucms_session_encrypted';

// 存储会话（加密后）
function saveSession(sessionData) {
    const encrypted = encrypt(JSON.stringify(sessionData));
    localStorage.setItem(SESSION_KEY, encrypted);
}

// 加载会话（解密并验证）
function loadSession() {
    try {
        const encrypted = localStorage.getItem(SESSION_KEY);
        if (!encrypted) return null;

        const decrypted = decrypt(encrypted);
        const stored = JSON.parse(decrypted);

        // 增强验证：检查 token、username、expiry 等
        if (stored && 
            typeof stored.token === 'string' && 
            typeof stored.username === 'string' &&
            stored.expiry > Date.now()) { // 添加过期检查
            return stored;
        }
    } catch (error) {
        console.error('Session load failed:', error);
        return null;
    }
    return null;
}
```

**注意**：最佳实践是避免在客户端存储敏感会话数据，优先采用服务器端会话管理。
